(async () => {
    try {
      try { await Filesystem.requestPermissions() } catch { /* ignore */ }
      invalidateSessionCache()

      const scannedFiles: ScannedFile[] = []

      async function scanDir(path: string, depth = 0) {
        if (depth >= 10) return
        try {
          onProgress?.({ found: scannedFiles.length, currentDir: (path ?? '').split('/').pop() || 'unknown', phase: 'scanning' })
          const result = await Filesystem.readdir({ path, directory: Directory.ExternalStorage })
          for (const entry of result.files) {
            if (entry.name.includes('..')) {
              onProgress?.({ found: scannedFiles.length, currentDir: path, phase: 'scanning' })
              continue
            }
            const fullPath = `${path}/${entry.name}`
            if (entry.type === 'directory') {
              await scanDir(fullPath, depth + 1)
            } else {
              const ext = entry.name.split('.').pop()?.toLowerCase() ?? ''
              if (AUDIO_EXTENSIONS.has(ext)) {
                scannedFiles.push({
                  name: entry.name,
                  path: fullPath,
                  size: entry.size ?? 0,
                  mtime: entry.mtime ?? 0,
                })
                onProgress?.({ found: scannedFiles.length, currentDir: (path ?? '').split('/').pop() || 'unknown', phase: 'scanning' })
              }
            }
          }
        } catch (err: unknown) {
          const msg = err instanceof Error ? err.message : String(err)
          if (msg.includes('EACCES') || msg.includes('SecurityException') || msg.includes('permission')) {
            onProgress?.({ found: scannedFiles.length, currentDir: (path ?? '').split('/').pop() || 'unknown', phase: 'scanning' })
          }
        }
      }

      for (const root of SCAN_ROOTS) await scanDir(root)

      onProgress?.({ found: scannedFiles.length, currentDir: '', phase: 'converting' })
      const idMap = await computeSessionIds(scannedFiles.map(f => f.path))
      const scanned = scannedFiles.map(f => fileMetaToSession(f, idMap.get(f.path)!))
      const merged = await mergeWithExisting(scanned)

      onProgress?.({ found: merged.length, currentDir: '', phase: 'saving' })
      saveFilePaths(merged)
      await saveAllSessions(merged)

      // 메타데이터 파생 (U-M06 음성 환경 + U-M07 통화 패턴)
      try { refreshDerivedMetadata(merged) } catch { /* non-critical */ }

      const totalBytes = scannedFiles.reduce((sum, f) => sum + f.size, 0)
      const filePaths: Record<string, string> = {}
      for (const s of merged) {
        if (s.callRecordId) filePaths[s.id] = s.callRecordId
      }

      onProgress?.({ found: merged.length, currentDir: '', phase: 'done' })
      return { sessions: merged, filePaths, totalBytes }
    } finally {
      deviceScanLock = null
    }
  })

(async () => {
    try {
      const dirHandle = await (window as any).showDirectoryPicker()
      invalidateSessionCache()

      const scannedFiles: ScannedFile[] = []

      async function scanDir(dh: any, currentPath: string, depth = 0) {
        if (depth >= 10) return
        onProgress?.({ found: scannedFiles.length, currentDir: currentPath, phase: 'scanning' })
        for await (const handle of dh.values()) {
          const childPath = `${currentPath}/${handle.name}`
          if (handle.kind === 'file') {
            const ext = handle.name.split('.').pop()?.toLowerCase() ?? ''
            if (AUDIO_EXTENSIONS.has(ext)) {
              const file = await handle.getFile()
              scannedFiles.push({
                name: handle.name,
                path: childPath,
                size: file.size,
                mtime: file.lastModified ?? 0,
              })
              onProgress?.({ found: scannedFiles.length, currentDir: currentPath, phase: 'scanning' })
            }
          } else if (handle.kind === 'directory') {
            await scanDir(handle, childPath, depth + 1)
          }
        }
      }

      await scanDir(dirHandle, dirHandle.name)

      onProgress?.({ found: scannedFiles.length, currentDir: '', phase: 'converting' })
      const idMap = await computeSessionIds(scannedFiles.map(f => f.path))
      const scanned = scannedFiles.map(f => fileMetaToSession(f, idMap.get(f.path)!))
